import{_ as i,c as a,o as e,ah as o}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/开发工具/gogcli-开发工具.md","filePath":"github汇总/开发工具/gogcli-开发工具.md"}'),r={name:"github汇总/开发工具/gogcli-开发工具.md"};function t(h,l,n,s,c,d){return e(),a("div",null,l[0]||(l[0]=[o('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>gogcli</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>steipete</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>开发工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>需要在终端中访问Google的各种服务，进行脚本自动化和日常操作，而不需要打开浏览器。</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>访问Gmail：搜索线程/消息、发送邮件、查看附件、管理标签/草稿/过滤器/委托/假期设置</li><li>访问Calendar：列出/创建/更新/删除事件、管理邀请、别名、订阅、团队日历等</li><li>访问Chat：列出/查找/创建空间、列出消息/线程、发送消息和DM、管理表情反应</li><li>访问Classroom：管理课程、名册、课程作业/材料、提交、公告、主题、邀请、监护人、个人资料</li><li>访问Drive：列出/搜索/上传/下载文件、替换上传、转换上传、管理权限/评论、组织文件夹</li><li>访问Contacts：搜索/创建/更新联系人，包括地址、关系、组织/职位元数据、自定义字段</li><li>访问Tasks：管理任务列表和任务：获取/创建/添加/更新/完成/撤销/删除/清除</li><li>访问Sheets：读/写/更新电子表格、插入行/列、管理标签和命名范围、格式化/合并/冻结/调整单元格大小</li><li>访问Forms：创建/更新表单、管理问题、检查响应、管理监视</li><li>访问Apps Script：创建/获取/绑定项目、检查内容、运行函数</li><li>访问Docs/Slides：创建/复制/导出文档/幻灯片、编辑文档、导入Markdown、导出文档为Markdown/HTML</li><li>访问People：个人资料查找和目录搜索帮助</li><li>访问Keep：列出/获取/搜索/创建/删除笔记和下载附件</li><li>访问Admin：Workspace Admin用户/组命令，用于常见目录操作</li><li>访问Groups：列出你所属的组，查看组成员</li><li>本地时间：为脚本和代理显示快速本地/UTC时间</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>多账户支持：同时管理多个Google账户，支持账户别名和每个客户端的OAuth存储桶</li><li>命令允许列表：限制沙盒/代理运行的顶级命令</li><li>安全的凭证存储：使用OS密钥环或加密的磁盘密钥环</li><li>自动刷新令牌：一次认证，无限期使用</li><li>灵活的认证：OAuth刷新令牌、ADC、直接访问令牌、服务账户、手动/远程流程</li><li>最少权限认证：--readonly、--drive-scope和--gmail-scope请求更少的范围</li><li>JSON优先输出：便于脚本和自动化</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/steipete/gogcli" target="_blank" rel="noreferrer">https://github.com/steipete/gogcli</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于需要在终端中访问Google服务的开发者和用户，支持Linux、macOS和Windows。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：Linux、macOS或Windows</li><li>依赖：Git（从源代码构建时需要）</li><li>权限要求：有足够的权限安装软件</li></ol><h2 id="主路径-安装与启动" tabindex="-1">主路径：安装与启动 <a class="header-anchor" href="#主路径-安装与启动" aria-label="Permalink to “主路径：安装与启动”">​</a></h2><h3 id="通过homebrew安装" tabindex="-1">通过Homebrew安装 <a class="header-anchor" href="#通过homebrew安装" aria-label="Permalink to “通过Homebrew安装”">​</a></h3><ol><li><strong>安装gogcli</strong><ul><li>执行位置：终端</li><li>完整命令：<code>brew install gogcli</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查Homebrew是否正确安装</li></ul></li></ol><h3 id="通过arch-user-repository安装" tabindex="-1">通过Arch User Repository安装 <a class="header-anchor" href="#通过arch-user-repository安装" aria-label="Permalink to “通过Arch User Repository安装”">​</a></h3><ol><li><strong>安装gogcli</strong><ul><li>执行位置：终端</li><li>完整命令：<code>yay -S gogcli</code></li><li>成功标志：安装完成，无错误信息</li><li>失败处理：检查yay是否正确安装</li></ul></li></ol><h3 id="从源代码构建" tabindex="-1">从源代码构建 <a class="header-anchor" href="#从源代码构建" aria-label="Permalink to “从源代码构建”">​</a></h3><ol><li><p><strong>克隆仓库</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>git clone https://github.com/steipete/gogcli.git</code></li><li>成功标志：仓库克隆成功</li><li>失败处理：检查网络连接</li></ul></li><li><p><strong>构建项目</strong></p><ul><li>执行位置：项目目录</li><li>完整命令：<code>cd gogcli &amp;&amp; make</code></li><li>成功标志：构建完成，无错误信息</li><li>失败处理：检查系统环境是否满足要求</li></ul></li><li><p><strong>运行gogcli</strong></p><ul><li>执行位置：项目目录</li><li>完整命令：<code>./bin/gog --help</code></li><li>成功标志：显示帮助信息</li><li>失败处理：检查构建是否成功</li></ul></li></ol><h2 id="配置与使用" tabindex="-1">配置与使用 <a class="header-anchor" href="#配置与使用" aria-label="Permalink to “配置与使用”">​</a></h2><h3 id="获取oauth2凭证" tabindex="-1">获取OAuth2凭证 <a class="header-anchor" href="#获取oauth2凭证" aria-label="Permalink to “获取OAuth2凭证”">​</a></h3><ol><li><p><strong>创建Google Cloud项目</strong></p><ul><li>执行位置：浏览器</li><li>操作：访问 <a href="https://console.cloud.google.com/projectcreate" target="_blank" rel="noreferrer">https://console.cloud.google.com/projectcreate</a> 创建项目</li><li>成功标志：项目创建成功</li><li>失败处理：检查Google Cloud Console访问权限</li></ul></li><li><p><strong>启用API</strong></p><ul><li>执行位置：浏览器</li><li>操作：启用需要的API，如Gmail API、Calendar API、Drive API等</li><li>成功标志：API启用成功</li><li>失败处理：检查项目权限</li></ul></li><li><p><strong>配置OAuth同意屏幕</strong></p><ul><li>执行位置：浏览器</li><li>操作：访问 <a href="https://console.cloud.google.com/auth/branding" target="_blank" rel="noreferrer">https://console.cloud.google.com/auth/branding</a> 配置OAuth同意屏幕</li><li>成功标志：配置完成</li><li>失败处理：检查项目设置</li></ul></li><li><p><strong>创建OAuth客户端</strong></p><ul><li>执行位置：浏览器</li><li>操作：访问 <a href="https://console.cloud.google.com/auth/clients" target="_blank" rel="noreferrer">https://console.cloud.google.com/auth/clients</a> 创建桌面应用类型的OAuth客户端</li><li>成功标志：客户端创建成功，下载JSON文件</li><li>失败处理：检查项目配置</li></ul></li></ol><h3 id="存储凭证" tabindex="-1">存储凭证 <a class="header-anchor" href="#存储凭证" aria-label="Permalink to “存储凭证”">​</a></h3><ol><li><strong>存储OAuth客户端凭证</strong><ul><li>执行位置：终端</li><li>完整命令：<code>gog auth credentials ~/Downloads/client_secret_....json</code></li><li>成功标志：凭证存储成功</li><li>失败处理：检查文件路径是否正确</li></ul></li></ol><h3 id="授权账户" tabindex="-1">授权账户 <a class="header-anchor" href="#授权账户" aria-label="Permalink to “授权账户”">​</a></h3><ol><li><p><strong>授权账户</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>gog auth add you@gmail.com</code></li><li>成功标志：浏览器打开OAuth授权页面，授权完成后返回终端</li><li>失败处理：检查网络连接，确保浏览器可以打开</li></ul></li><li><p><strong>无头/远程服务器流程</strong></p><ul><li>执行位置：终端</li><li>完整命令：<code>gog auth add you@gmail.com --services user --manual</code></li><li>成功标志：终端打印认证URL，在本地浏览器打开并授权，然后将重定向URL粘贴回终端</li><li>失败处理：检查网络连接</li></ul></li></ol><h3 id="测试认证" tabindex="-1">测试认证 <a class="header-anchor" href="#测试认证" aria-label="Permalink to “测试认证”">​</a></h3><ol><li><strong>测试认证</strong><ul><li>执行位置：终端</li><li>完整命令：<code>export GOG_ACCOUNT=you@gmail.com &amp;&amp; gog gmail labels list</code></li><li>成功标志：显示Gmail标签列表</li><li>失败处理：检查认证是否成功</li></ul></li></ol><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><ul><li>执行命令：<code>gog --version</code></li><li>预期返回：显示gogcli版本</li></ul><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>认证失败</strong></p><ul><li>现象：执行命令后出现认证错误</li><li>可能原因：OAuth凭证过期、权限不足</li><li>解决步骤：重新授权账户，确保启用了所需的API</li></ul></li><li><p><strong>API调用失败</strong></p><ul><li>现象：执行命令后出现API错误</li><li>可能原因：API未启用、权限不足</li><li>解决步骤：检查是否启用了所需的API，确保授权时请求了正确的范围</li></ul></li><li><p><strong>依赖安装失败</strong></p><ul><li>现象：从源代码构建时出现依赖错误</li><li>可能原因：缺少必要的依赖</li><li>解决步骤：检查系统环境，安装所需的依赖</li></ul></li></ol><h2 id="备选部署路径" tabindex="-1">备选部署路径 <a class="header-anchor" href="#备选部署路径" aria-label="Permalink to “备选部署路径”">​</a></h2><p>README/仓库信息中未提供其他部署方式。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README/仓库信息中未提供完整的API启用教程，上述教程基于README中提到的安装方式整理。</p>',45)]))}const u=i(r,[["render",t]]);export{p as __pageData,u as default};
